import React from "react";

function Login() {
  return (
    <div>
      <h2>Hospital Management System Login</h2>
      <button>Login as Admin</button>
      <button>Login as Receptionist</button>
      <button>Login as Doctor</button>
    </div>
  );
}

export default Login;
